def find_duplicate_elements(nums, k):
    elements_dict = {}
    duplicates = []

    for i, num in enumerate(nums):
        if num in elements_dict and i - elements_dict[num] <= k:
            duplicates.append((num, elements_dict[num], i))
        else:
            elements_dict[num] = i

    return duplicates


