import os
import shutil

def setup_dirs(test_file):
    test_dir = os.path.dirname(test_file)
    indir = os.path.join(test_dir, 'input')
    workdir = os.path.join(test_dir, 'work')
    outdir = os.path.join(test_dir, 'output')
    os.makedirs(indir, exist_ok=True)
    os.makedirs(workdir, exist_ok=True)
    os.makedirs(outdir, exist_ok=True)
    return indir, workdir, outdir

class FastaParser:
    def __init__(self, file_path):
        self.file_path = file_path

    def __enter__(self):
        self.file = open(self.file_path, 'r')
        return self

    def __exit__(self, exc_type, exc_value, traceback):
        self.file.close()

    def __iter__(self):
        self.identifier = None
        self.sequence = []
        for line in self.file:
            line = line.strip()
            if line.startswith('>'):
                if self.identifier:
                    yield (self.identifier, ''.join(self.sequence))
                    self.sequence = []
                self.identifier = line[1:]
            else:
                self.sequence.append(line)
        if self.identifier:
            yield (self.identifier, ''.join(self.sequence))

    def setUp(self):
        self.indir, self.workdir, self.outdir = setup_dirs(__file__)

    def tearDown(self):
        shutil.rmtree(self.workdir)
        shutil.rmtree(self.outdir)

    def test_iteration(self):
        with FastaParser(f'{self.indir}/test.fa') as parser:
            for identifier, sequence in parser:
                print(f'Sequence ID: {identifier}, Sequence: {sequence}')
```
