Here is the corrected JavaScript procedure that utilizes recursion, produces the desired cubic sequence, and handles erroneous or negative inputs:

```javascript
function cubicSequence(n) {
    // Error handling for erroneous or negative inputs
    if(typeof n !== 'number' || n<1) throw new Error('Input must be a positive integer');

    // cast n to integer just in case if it's not
    n = Math.floor(n);

    // Base case for recursion. If n is 1, return an array with its cube.
    if(n === 1) return [1];

    // Recursive call for n-1
    const arr = cubicSequence(n-1);

    // Push the cube of n to the array and return the result
    arr.push(n * n * n);
    return arr;
}
