    void sort(int arr[]) {
        int n = arr.length;

        //iterate over the array to build the heap 
        for (int i = n / 2 - 1; i >= 0; i--)
            //calling heapify method
            heapify(arr, n, i);

        // Extract elements from the heap
        for (int i=n-1; i>=0; i--) {
            // Swap current root element with end element
            int temp = arr[0];
            arr[0] = arr[i];
            arr[i] = temp;

            // Heapify the reduced heap
            heapify(arr, i, 0);
        }
    }

    //method to build a heap from array
    void heapify(int arr[], int heapSize, int root) {
        int largest = root;  // Initialize largest as root
        int leftChild = 2 * root + 1;  
        int rightChild = 2 * root + 2;  

        // If leftChild is larger than largest
        if (leftChild < heapSize && arr[leftChild] > arr[largest])
            largest = leftChild;

        // If rightChild is larger than largest
        if (rightChild < heapSize && arr[rightChild] > arr[largest])
            largest = rightChild;

        // If largest is not root, swap with root and heapify the affected sub-tree
        if (largest != root) {
            // Swap root with largest
            int swap = arr[root];
            arr[root] = arr[largest];
            arr[largest] = swap;

            // Recursively heapify the affected sub-tree
            heapify(arr, heapSize, largest);
        }
    }

