```javascript
function extractWordsWithLetter(sentence, letter) {
  const vowels = ['a', 'e', 'i', 'o', 'u'];
  const words = sentence.split(' ');
  const extractedWords = [];
  let count = 0;

  for (let word of words) {
    const firstChar = word.charAt(0).toLowerCase();
    const lastChar = word.charAt(word.length - 1).toLowerCase();

    if (!vowels.includes(firstChar) && !isConsonant(lastChar) && word.includes(letter)) {
      extractedWords.push(word);
      count += countOccurrences(word, letter);
    }
  }

  return {
    extractedWords,
    count
  };
}

function isConsonant(char) {
  return !'aeiou'.includes(char);
}

function countOccurrences(word, letter) {
  return word.split(letter).length - 1;
}

// Example usage:
const sentence = "The quick brown fox jumps over the lazy dog's tail";
const letter = 'o';
const result = extractWordsWithLetter(sentence, letter);
console.log(result.extractedWords); // Output: ["brown", "fox", "over", "dog's"]
console.log(result.count); // Output: 4
```

