class VendingMachine:
    def __init__(self):
        self.stock = {}  # Dictionary to store stocked items {item_name: (quantity, price)}
        self.total_money_inserted = 0  # Total money inserted by the user

    def stock_item(self, item_name, quantity, price):
        if quantity < 0 or price < 0:
            raise ValueError("Quantity and price must be non-negative")
        if item_name in self.stock:
            current_quantity, current_price = self.stock[item_name]
            self.stock[item_name] = (current_quantity + quantity, current_price)
        else:
            self.stock[item_name] = (quantity, price)

    def insert_coin(self, coin):
        if coin < 0:
            raise ValueError("Invalid coin value")
        self.total_money_inserted += coin

    def purchase_item(self, item_name):
        if item_name not in self.stock:
            return "Item out of stock"
        quantity, price = self.stock[item_name]
        if quantity == 0:
            return "Item out of stock"
        if self.total_money_inserted < price:
            return "Insufficient funds"
        self.total_money_inserted -= price
        self.stock[item_name] = (quantity - 1, price)
        change = self.return_change()
        return f"Dispensing {item_name}. Change: {change}"

    def return_change(self):
        change = self.total_money_inserted
        self.total_money_inserted = 0
        return change
