```c
#include <stdio.h>
#include <string.h>

int main(int argc, char *argv[]) {
    if(argc == 1) {
        printf("No command-line arguments are provided.\n");
        return 0;
    }

    int max_len = strlen(argv[1]);
    int min_len = strlen(argv[1]);
    int cumulative_len = 0;
    int max_index = 1;
    int min_index = 1;

    for(int i = 1; i < argc; i++) {
        int len = strlen(argv[i]);
        cumulative_len += len;

        if(len > max_len) {
            max_len = len;
            max_index = i;
        } 
        if(len < min_len) {
            min_len = len;
            min_index = i;
        } 
    }

    printf("Total arguments: %d\n", argc - 1);
    printf("The argument with maximum characters: %s, Length: %d\n", argv[max_index], max_len);
    printf("The argument with minimum characters: %s, Length: %d\n", argv[min_index], min_len);
    printf("Cumulative length of all arguments: %d\n", cumulative_len);

    return 0;
}
```

