            if specialty not in self.specialties:
                self.specialties.append(specialty)

    def update_skill_level(self, new_skill_level):
        self.skill_level = new_skill_level

# Let's test this again.
demo_chef = ItalianChef(['Pasta', 'Pizza', 'Tiramisu'], 'Expert')
demo_chef.update_specialties(['Lasagna', 'Pizza'])
demo_chef.update_skill_level('Master')
demo_chef.describe()
